var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"오늘은 주인님을 위해 이렇게 꽃을 가져왔답니다.","JPN":"今日はご主人様のために花を持ってきました。","ENG":"Today I've brought these flowers for you, Master.","TWN":"我今天要送花給主人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주제넘는다고 여기실 수도 있겠지만...... 이 꽃으로 주인님의 방을 장식해도 괜찮을까요?","JPN":"差し出がましいと思われるかもしれませんが……ご主人様のお部屋に飾ってもよろしいでしょうか。","ENG":"Would you mind if I decorated your room with them?","TWN":"您可以允許我……用這朵花裝飾主人的房間嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"감사합니다. 드라이플라워도 충분히 아름답지만, 이번엔 생화를 화병에 담아봤어요.","JPN":"ありがとうございます。ドライフラワーも充分キレイですが、今回は生け花を花瓶にさしてみました。","ENG":"Thank you. Dried flowers are beautiful in their own way, but this time, I've brought fresh ones in a vase.","TWN":"謝謝您。乾燥花雖然也足夠美麗，但這次我在花瓶裡裝飾了鮮花。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이렇게 두니 방이 한층 더 생기가 도는 것 같지 않나요?","JPN":"こうすると、お部屋の雰囲気も一層鮮やかになったと思いませんか？","ENG":"There. Doesn't your room look livelier than before?","TWN":"房間是不是變得更有活力了？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"여기, 메모에 꽃을 관리하는 법에 대해 간단히 적어두었습니다.","JPN":"こちらのメモに、花のお手入れ方法について簡単にまとめておきました。","ENG":"Here, I wrote down how to take care of the flowers on this paper.","TWN":"我在這裡寫了養花的注意事項。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"물갈이를 하러 메이드가 방에 자주 출입하면 아무래도 불편하실 테니까요.","JPN":"水替えをしにメイドが頻繁に出入りすると、ご不便をおかけすることになりますから。","ENG":"In case you don't want me coming into your room to change the water all the time.","TWN":"女僕為了換水出入您的房間，難免有些不方便。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이 꽃들은 섬세하지만, 주인님이라면 분명 잘 보살필 수 있으실 겁니다.","JPN":"この花は繊細ですが、ご主人様ならきっと上手にお手入れしてくださると思います。","ENG":"These flowers are delicate, but I believe you will take good care of them.","TWN":"這些花很敏感，但主人一定可以照顧好它們的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그럼 본 용무로 돌아가실까요. 종신계약이라는 언질은 받았습니다.","JPN":"では、さっそく本題に入りましょうか。終身契約ということは聞いております。","ENG":"Now, back to the main topic. I've been told that this is about a lifetime contract.","TWN":"回歸正題吧，我收到了簽訂終身雇傭的提議。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그럼 제가 곁에서 주인님을 계속 보필하는 것을 허락해 주신단 말씀이군요.","JPN":"では、私がこれからもずっとご主人様に仕えることを許していただけるのですね。","ENG":"That means, you'll let me continue to serve by your side.","TWN":"這麼說，您允許我繼續在您身邊輔佐您是嗎。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"물론 메이드로선 더할 나위 없이 기쁜 제안이랍니다.","JPN":"もちろん、メイドとしてこれ以上嬉しいご提案はありません。","ENG":"As your maid, this is the most exciting offer I've ever had.","TWN":"我作為女僕，非常高興能得到這樣的提議。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"한낱 계약서로 어떻게 제 충의를 증명하겠습니까만, 주인님께서 만족하신다면 얼마든지요.","JPN":"たった一枚の契約書では私の忠誠心を証明しきれないと思いますが、ご主人様に満足していただけるなら、いくらでも。","ENG":"There's no contract that can prove my loyalty to you, but I'll sign it if that makes you happy.","TWN":"一個合同怎麼能夠證明我的忠心呢，只要主人您滿意就可以了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이건...... 주인님 방의 키카드인가요?","JPN":"これは……ご主人様の部屋のカードキーですか？","ENG":"This... Is this the keycard to your room?","TWN":"這是……主人房間的房卡嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"메모보단 제게 직접 꽃에 대해 배우고 싶으시다고요?","JPN":"メモより、私から直接花について教わりたいのですか？","ENG":"You don't want this memo; you want to learn directly from me?","TWN":"您說不想讀便條，想讓我親自教你養花？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"후훗, 그렇군요.","JPN":"ふふっ、そうですか。","ENG":"Hah hah. I see.","TWN":"呼呼，原來如此。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님께선 그저 꽃들의 아름다움을 즐겨주시기만 해도 될 텐데...... 그렇게까지 제 성의에 신경을 써주시다니.","JPN":"ご主人様は、花の美しさを堪能していただくだけで充分なのに……そこまで私を気にしてくださるとは。","ENG":"You could just enjoy the flowers and let me take care of them, but instead you want to learn to take care of them yourself, from me.","TWN":"其實主人您只需欣賞美麗的花朵就足夠了……沒想到如此在意我的誠意。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"걱정 마시길. 이 방의 꽃들이 시드는 일이 없도록 책임지고 가르쳐드리겠습니다.","JPN":"ご心配なく。この部屋の花が枯れることはないよう、責任持ってお教えします。","ENG":"Don't worry. I'll gladly teach you how to take care of the flowers and keep them fresh for as long as possible.","TWN":"請您放心，我會全力指導您，絕不會讓這個房間的花朵凋謝的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그럼 부디, 오늘도 향기로운 하루 되시길.","JPN":"では、今日も香りに満ちた一日になりますように。","ENG":"Now, enjoy a fragrant day today.","TWN":"希望您今天也度過芬芳的一天。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};